        subparts: [
            'Given: y = 4x³ - 2x² + 7x - 5',
            'Differentiate term by term:',
            'd/dx(4x³) = 12x²',
            'd/dx(-2x²) = -4x',
            'd/dx(7x) = 7',
            'd/dx(-5) = 0',
            'Combine:',
            'dy/dx = 12x² - 4x + 7',
            'Answer: dy/dx = 12x² - 4x + 7'
        ],
        helper: 'Derivative of sum = sum of derivatives',
